"""
LeetCode 542 - 01 Matrix
https://leetcode.com/problems/01-matrix/

"""
from typing import List
from collections import deque

class Solution:
	def updateMatrix(self, mat: List[List[int]]) -> List[List[int]]:
		M, N = len(mat), len(mat[0])
		dirs = ((1, 0), (0, 1), (-1, 0), (0, -1))
		q = deque()
		for x in range(M):
			for y in range(N):
				if mat[x][y] == 0:
					q.append((x, y))
				else:
					mat[x][y] = float("inf")
		while q:
			x, y = q.popleft()
			for dx, dy in dirs:
				nx, ny = x + dx, y + dy
				if 0 <= nx < M and 0 <= ny < N and mat[nx][ny] == float("inf"):
					q.append((nx, ny))
					mat[nx][ny] = mat[x][y] + 1
		return mat


sol = Solution()

